export type BookLevel = 'a1' | 'a2' | 'b1';

export const BOOK_LEVEL_LABELS: Record<BookLevel, string> = {
  a1: 'A1',
  a2: 'A2',
  b1: 'B1',
};

export const BOOK_LEVEL_COLORS: Record<BookLevel, string> = {
  a1: '#34D399',
  a2: '#FBBF24',
  b1: '#F87171',
};

export const BOOK_LEVELS_ORDER: BookLevel[] = ['a1', 'a2', 'b1'];

export type StoryParagraph = { en: string; uz: string };
export type BookStory = {
  id: string;
  level: BookLevel;
  title: string;
  emoji: string;
  colors: [string, string];
  description: string;
  paragraphs: StoryParagraph[];
};

function slug(title: string): string {
  return title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
}

const COLOR_PAIRS: [string, string][] = [
  ['#9B7BFF', '#6B4FE0'],
  ['#F87171', '#F59E0B'],
  ['#D879E8', '#A855F7'],
  ['#FBBF24', '#D97706'],
  ['#34D399', '#059669'],
  ['#60A5FA', '#2563EB'],
  ['#F472B6', '#DB2777'],
  ['#FB923C', '#EA580C'],
  ['#38BDF8', '#0284C7'],
  ['#A78BFA', '#7C3AED'],
  ['#4ADE80', '#16A34A'],
  ['#FCA5A5', '#DC2626'],
];

let colorCounter = 0;
function nextColors(): [string, string] {
  const c = COLOR_PAIRS[colorCounter % COLOR_PAIRS.length];
  colorCounter += 1;
  return c;
}

function S(en: string, uz: string): StoryParagraph {
  return { en, uz };
}

function story(
  level: BookLevel,
  title: string,
  emoji: string,
  description: string,
  paragraphs: StoryParagraph[]
): BookStory {
  return { id: slug(title), level, title, emoji, colors: nextColors(), description, paragraphs };
}

